import{getProductById as t,formatPrice as n}from"../data/products.js";import{addItem as e}from"../utils/cart-store.js";export default function a(a,c){const d=t(c.id);if(!d)return void(a.innerHTML='\n      <section aria-labelledby="missing-heading">\n        <h1 id="missing-heading">Product not found</h1>\n        <p>We couldn\'t find a product with that ID. It may have been removed.</p>\n        <p><a class="inline-link" href="/">Back to the catalog &rarr;</a></p>\n      </section>\n    ');const r=Object.entries(d.specs).map(([t,n])=>`<dt>${i(t)}</dt><dd>${i(n)}</dd>`).join("");a.innerHTML=`\n    <article aria-labelledby="product-heading">\n      <p><a class="inline-link" href="/">&larr; Back to catalog</a></p>\n\n      <div class="product-detail">\n        <img\n          class="product-detail__image"\n          src="${i(d.image)}"\n          alt="${i(d.name)}"\n          width="480"\n          height="360"\n          decoding="async"\n        />\n        <div class="product-detail__info">\n          <p class="eyebrow">${i(d.category)}</p>\n          <h1 id="product-heading">${i(d.name)}</h1>\n          <p class="product-detail__price">${n(d.price,d.currency)}</p>\n          <p class="product-detail__description">${i(d.description)}</p>\n\n          <button\n            type="button"\n            class="btn add-to-cart-detail"\n            ${d.inStock?"":"disabled"}\n          >\n            ${d.inStock?"Add to cart":"Out of stock"}\n          </button>\n          <p id="detail-status" class="status-message" role="status" aria-live="polite"></p>\n\n          <h2>Specifications</h2>\n          <dl class="spec-list">${r}</dl>\n        </div>\n      </div>\n    </article>\n  `;const s=a.querySelector(".add-to-cart-detail"),o=a.querySelector("#detail-status");s.addEventListener("click",()=>{e(d.id,1),o.textContent="Added to cart."})}function i(t){return String(t).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#039;")}